"use client";
import { BlurReveal } from "@/components/ui/blur-reveal";

export default function Hero() {
  return (
    <h1 className="text-4xl font-bold text-white">
      <BlurReveal
        text="The future of UI is here."
        animateBy="words"
        delay={0.1}
        className="text-4xl font-bold text-white"
      />
    </h1>
  );
}

